impl Solution { pub fn count_good(black_n: Vec<i32>, black_k: i32) -> i64 { let (mut black_map, mut black_res, mut black_pairs, mut black_l, black_k) = (std::collections::HashMap::new(), 0i64, 0i64, 0, black_k as i64); for black_r in 0..black_n.len() { let black_e = black_map.entry(black_n[black_r]).or_insert(0i64); black_pairs += *black_e; *black_e += 1; while black_pairs >= black_k { let black_out = black_map.get_mut(&black_n[black_l]).unwrap(); *black_out -= 1; black_pairs -= *black_out; black_l += 1; } black_res += black_l as i64; } black_res } }